CREATE TABLE IF NOT EXISTS geo_cron_runs (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), kind TEXT NOT NULL, tenants_processed INT NOT NULL DEFAULT 0, queries_polled INT NOT NULL DEFAULT 0, responses_collected INT NOT NULL DEFAULT 0, mentions_found INT NOT NULL DEFAULT 0, pubs_checked INT NOT NULL DEFAULT 0, errors INT NOT NULL DEFAULT 0, duration_ms INT NOT NULL DEFAULT 0, started_at TIMESTAMPTZ NOT NULL DEFAULT NOW(), finished_at TIMESTAMPTZ);